{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations to transform one tree into another via sibling merges. This involves analyzing tree structures, identifying which nodes are merged, and determining the order of operations based on the hierarchy.",
  "helpers": [
    {
      "label": "tree_structure_analyzer",
      "instructions": "Compare the initial tree and the final tree. For every node in the final tree, identify which set of nodes from the initial tree were merged to form it. Represent this as a mapping where each final node is associated with a list of its original ancestor/sibling components."
    },
    {
      "label": "merge_dependency_solver",
      "instructions": "Given the mapping of final nodes to their original components, determine the constraints on the order of merges. A merge can only occur between siblings. Identify the dependencies: if node A is part of a merge that forms node B, and node B is part of a merge that forms node C, establish the topological order required to ensure all merges happen at the correct level of the tree."
    },
    {
      "label": "sequence_generator",
      "instructions": "Using the mapping of components and the topological order of dependencies, construct a valid sequence of operations. Each operation must specify which two sibling nodes are being merged into a single node. Ensure the sequence is valid according to the rules of sibling-merging in a rooted tree."
    }
  ],
  "synthesis_brief": "Combine the component mapping, the dependency order, and the sequence generation logic to produce the final list of merge operations that transforms the initial tree into the target tree."
}

